import React, { useEffect, useState } from 'react';
import api from '../api';

const AppointmentList = () => {
  const [appointments, setAppointments] = useState<any[]>([]);
  const [patients, setPatients] = useState<any[]>([]);
  const [doctors, setDoctors] = useState<any[]>([]);
  
  const [selectedPat, setSelectedPat] = useState('');
  const [selectedDoc, setSelectedDoc] = useState('');
  const [appDate, setAppDate] = useState('');
  const [status, setStatus] = useState('Pending');

  const fetchData = async () => {
    const [resApp, resPat, resDoc] = await Promise.all([
      api.get('appointments/'),
      api.get('patients/'),
      api.get('doctors/')
    ]);
    setAppointments(resApp.data);
    setPatients(resPat.data);
    setDoctors(resDoc.data);
  };

  useEffect(() => { fetchData(); }, []);

  const handleAdd = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      // Nagpadala og IDs para sa Foreign Keys
      await api.post('appointments/', {
        patient: selectedPat,
        doctor: selectedDoc,
        appointment_date: appDate,
        status: status
      });
      setSelectedPat(''); setSelectedDoc(''); setAppDate('');
      fetchData();
      alert("Appointment Scheduled!");
    } catch (err: any) {
      console.error("Appointment Error:", err.response?.data);
    }
  };

  return (
    <div className="space-y-4">
      <form onSubmit={handleAdd} className="grid grid-cols-1 md:grid-cols-5 gap-2 bg-gray-50 p-4 rounded-lg">
        <select className="border p-2 rounded" value={selectedPat} onChange={e => setSelectedPat(e.target.value)} required>
          <option value="">Select Patient</option>
          {patients.map(p => <option key={p.patient_id} value={p.patient_id}>{p.first_name} {p.last_name}</option>)}
        </select>
        <select className="border p-2 rounded" value={selectedDoc} onChange={e => setSelectedDoc(e.target.value)} required>
          <option value="">Select Doctor</option>
          {doctors.map(d => <option key={d.doctor_id} value={d.doctor_id}>Dr. {d.last_name}</option>)}
        </select>
        <input type="datetime-local" className="border p-2 rounded" value={appDate} onChange={e => setAppDate(e.target.value)} required />
        <select className="border p-2 rounded" value={status} onChange={e => setStatus(e.target.value)}>
          <option value="Pending">Pending</option>
          <option value="Confirmed">Confirmed</option>
        </select>
        <button type="submit" className="bg-indigo-600 text-white p-2 rounded">Schedule</button>
      </form>
      <table className="min-w-full bg-white shadow rounded-lg">
        <thead className="bg-gray-100">
          <tr><th className="p-3 text-left">ID</th><th className="p-3 text-left">Patient</th><th className="p-3 text-left">Doctor</th><th className="p-3 text-left">Date</th></tr>
        </thead>
        <tbody>
          {appointments.map((a: any) => (
            <tr key={a.appointment_id} className="border-b">
              <td className="p-3">#{a.appointment_id}</td>
              <td className="p-3">{a.patient}</td>
              <td className="p-3">{a.doctor}</td>
              <td className="p-3">{new Date(a.appointment_date).toLocaleString()}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

export default AppointmentList;
